/* 生成NPC, By BlackStar, Ver.0.4.1 */
(()=>{"use strict";const defaultConfig={maxtrait:2};const generateNPC=(profiles,attrs,traits,config={},defaults={})=>{config=Object.assign({},defaultConfig,config);const npcAttrs={};for(const[key,value]of Object.entries(attrs)){if(Array.isArray(value)){const options={};value.forEach((range=>{options[`${range.min}-${range.max}`]=range.prob}));const range=drawOption(options);const[min,max]=range.split("-").map(Number);npcAttrs[key]=randomInt(min,max)}else{npcAttrs[key]=randomInt(value.min,value.max)}}const npcProfiles={};for(const[key,value]of Object.entries(profiles)){if(Array.isArray(value)&&value.length>0&&typeof value[0]==="object"&&value[0]!==null){let options={};value.forEach((option=>{options[option.value]=option.prob}));const option=drawOption(options);npcProfiles[key]=option;const chosenProfile=value.find((opt=>opt.value===option));if(chosenProfile.affects){for(const[attrKey,attrValue]of Object.entries(chosenProfile.affects)){npcAttrs[attrKey]+=attrValue}}}else{npcProfiles[key]=value.random()}}const applies=[];const map={};let available=[...traits];let count=0;while(applies.length<config.maxtrait&&available.length>0){if(count>0){available=available.filter((trait=>!applies.some((appliedTrait=>{const applied=map[appliedTrait];return applied.exclusive&&applied.exclusive.includes(trait.name)||trait.exclusive&&trait.exclusive.includes(appliedTrait)}))))}if(available.length===0)break;const trait=available.random();if(!(trait.name in map)){applies.push(trait.name);map[trait.name]=trait;available=available.filter((t=>t!==trait))}count++}for(const trait of Object.values(map)){for(const[key,value]of Object.entries(trait.affects)){if(npcAttrs[key]!==undefined){npcAttrs[key]+=value}}}return{...npcProfiles,...defaults,...npcAttrs,traits:applies}};setup.generateNPC=generateNPC;window.generateNPC=window.generateNPC||generateNPC})();
/* 生成NPC */